// // This module decrements a 9-bit binary counter on every positive edge of the clock signal, clk. The counter has an active-high synchronous load signal, load, and a 9-bit input, data_in. When load is asserted, the counter should load the value from data_in.
module counter_with_load (
	input clk,
	input load,
	input [8:0] data_in,
	output reg [8:0] count);

always @(posedge clk)
	if (load)
		count <= data_in;
	else
		count <= count + 1;

endmodule
